// OrderCartContext.js
import { useState, createContext, useContext, useEffect } from "react";

const OrderContext = createContext();

export const OrderProvider = ({ children }) => {
  // Initialize state from localStorage with error handling
  const [order, setOrder] = useState(() => {
    try {
      const savedOrder = localStorage.getItem("order");
      return savedOrder ? JSON.parse(savedOrder) : {};
    } catch (error) {
      console.error("Error loading order from localStorage:", error);
      return {};
    }
  });

  const [menu, setMenu] = useState([]);

  // Save to localStorage whenever order changes
  useEffect(() => {
    try {
      localStorage.setItem("order", JSON.stringify(order));
    } catch (error) {
      console.error("Error saving order to localStorage:", error);
    }
  }, [order]);

  const addToOrder = (productId, quantity) => {
    if (!menu) return;

    const product = menu.find(item => item.id === productId);
    if (!product) return;

    setOrder(prevOrder => {
      const currentQuantity = prevOrder[productId]?.quantity || 0;
      const newQuantity = Math.max(0, currentQuantity + quantity);

      if (newQuantity === 0) {
        const { [productId]: _, ...rest } = prevOrder;
        return rest;
      }

      return {
        ...prevOrder,
        [productId]: {
          id: product.id,
          name: product.item,
          price: product.price,
          description: product.description,
          quantity: newQuantity,
        },
      };
    });
  };

  const removeFromOrder = (productId) => {
    setOrder(prevOrder => {
      const { [productId]: _, ...rest } = prevOrder;
      return rest;
    });
  };

  const clearCart = () => {
    setOrder({});
  };

  const getItemQuantity = (productId) => {
    return order[productId]?.quantity || 0;
  };

  const getTotalAmount = () => {
    return Object.values(order).reduce((total, item) => {
      return total + (item.price * item.quantity);
    }, 0);
  };

  return (
    <OrderContext.Provider value={{
      order,
      addToOrder,
      removeFromOrder,
      clearCart,
      getItemQuantity,
      getTotalAmount,
      menu,
      setMenu
    }}>
      {children}
    </OrderContext.Provider>
  );
};

export const useOrderContext = () => useContext(OrderContext);
